import{S as r,i as l,s as i,j as c,m,o as p,E as u,x as f,u as g,v as d}from"./vendor-ea8ed43c.js";import{S as _,t as $}from"./iconographySetup-4e8e8521.js";import{d as s}from"./index-d573ac81.js";import"./linear-a465d416.js";import"./preload-helper-1153c41b.js";function h(o){let e,a,ttl="岁首农耕祈丰年",src="";if(o[2]==="tlalte2"){ttl="春龙降雨兆丰年";src=""}else if(o[2]==="tlalte3"){ttl="新米敬天报秋收";src=""}return e=new _({props:{title:ttl,source:src,sourceUrl:s.source_tlalte_url,name:o[2],imgPath:o[3],selected:0,steps:o[1],positions:$,imageRange:o[0]}}),{c(){c(e.$$.fragment)},l(t){m(e.$$.fragment,t)},m(t,n){p(e,t,n),a=!0},p:u,i(t){a||(f(e.$$.fragment,t),a=!0)},o(t){g(e.$$.fragment,t),a=!1},d(t){d(e,t)}}}function j(o,e,a){let{name:t="tlalte",imgPath:m="tu1zhong.svg"}=e;const i=[0,5320],l=t==="tlalte"?[{"id": "intro", "title": "年节", "text": "春节与各民族年节，庆祝岁首、祈福农耕。<br><br>年节是每个民族最重要的节日，春节是中国中最具影响力的年节，影响覆盖全民族；同时不少少数民族也有着独特且隆重的年节。年节是以一年为周期的起始、结束的节日为概念，这和传统农业农耕以一年为周期耕种、收获相吻合。"}, {"id": "cycle_timing", "title": "周期性", "text": "年节与当地农业周期关系紧密。包括春节在内的众农耕民族的年节起源于岁首日对旧年收成的庆祝与对新年农事顺利的祈福，如陕西地区就保留了谒庙、敬神，祈祷一年风调雨顺五谷丰登的仪式；苗族年节“罢谷节”则在秋收之后举行，喜庆一年劳作的丰收；"}, {"id": "hair", "title": "饮食", "text": "年节以庆祝一年劳作的收获为节日底色，因此常以宴会、年夜饭的形式进行庆祝，各地因此产生了各式各样的饮食习俗。壮族年节吃五色糯米饭以祝五谷丰登；藏族食用油饼、奶饼、酥油茶，并以\"竹素其玛\"（青稞糕点）为祭品。"}, {"id": "mouth", "title": "歌舞庙会", "text": "歌舞与庙会也是年节娱乐中重要的组成部分。陕西赤牛坬庙会流行抬神楼、转九曲、踢场子；苗族、侗族年节吹奏芦笙，跳踩堂舞；土家族年节举行隆重摆手舞会，以生活动作为舞姿；哈尼族、壮族、瑶族兴盛歌会，促青年男女交际。"}]:t==="tlalte2"?[{"id": "intro", "title": "龙抬头", "text": "祭祀龙王求雨，南方开耕北方驱虫避害。<br><br>龙抬头，又称春龙节，古称春耕节，定于农历二月初二，是古代农耕社会顺应天象、祈求丰年的重要民俗节点。龙抬头节日分布区域广，南北习俗差异大，在西南演化为祭龙节。"}, {"id": "claws", "title": "求雨祈雨", "text": "人们认为龙主司雨水，而龙抬头又是春耕关键时期，故有祭祀龙王、舞龙求雨的习俗，祈求风调雨顺、五谷丰登。纳西族于祭龙节在黑龙潭建龙神祠颂《祭龙王经》；藏族于龙王潭祭龙，以佳肴供养龙王，以划舟、歌舞来娱悦龙王。"}, {"id": "hair", "title": "南方春耕", "text": "南方地区开耕农时于龙抬头重合，古来就有“春耕节”之称，不少地区会举行\"开犁仪式\"。祭龙节更聚焦于祭祀龙神以换取对农事的保护，如哈尼族祭龙节需摆长龙宴，祭祀龙神；三月开耕前要举行“普龙户”祭龙天仪式。"}, {"id": "mouth", "title": "北方驱虫", "text": "北方民间认为“龙为百足之长”。龙抬头日，人们通过撒灰、熏艾、吃“龙食”（如面条为龙须，饼为龙鳞）等习俗，祈求驱除害虫、保护庄稼与家人健康。如山东地区二月二打房梁，意在惊走龙蛇、蝎子等毒虫。"}]:t==="tlalte3"?[{"id": "intro", "title": "吃新节", "text": "新米祭祀祖先，先敬狗后全家共尝丰收。<br><br>吃新节，又称尝新节、新米节，是流行于中国南方稻作民族（如苗族、布依族、侗族等）的传统农耕节日。通常在稻谷成熟、开镰收割前举行，旨在通过祭祀祖先、神灵，品尝新米，庆祝丰收并祈求来年风调雨顺。"}, {"id": "claws", "title": "祭祀祖先", "text": "吃新节的核心仪式是祭祀。人们会准备新米饭、肉类、酒等供品，祭拜祖先、土地神或谷神，感谢神灵庇佑带来丰收。如苗族在吃新节时，会由长者主持祭祀仪式，念诵祭词，邀请祖先回来享用新米。"}, {"id": "hair", "title": "敬狗习俗", "text": "许多民族在吃新节有“敬狗”的习俗。传说中，狗将稻种带给人间，因此在品尝新米前，要先给狗喂食第一碗新米饭和肉，以示感恩。这一习俗体现了人与动物和谐共处的农耕文化理念，如苗族、布依族都有此传说与习俗。"}, {"id": "mouth", "title": "尝新宴", "text": "祭祀仪式后，全家人会围坐在一起，共同品尝新米饭和丰盛的菜肴，这被称为“尝新宴”。这不仅是享受劳动成果的时刻，也是加强家族凝聚力、增进亲情的重要场合。邻里之间也会互相邀请，分享丰收的喜悦。"}]:s["tlalte-steps"];return[i,l,t,m]}class y extends r{constructor(e){super();l(this,e,j,h,i,{name:2,imgPath:3})}}export{y as default};

